namespace sv_a70394b665ce47cd97ebfa592edf5113.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service holding the current warehouse selection for one user circuit.
/// All interactive components on the same circuit share this instance.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A — East" },
        new() { Id = "WH-B", Name = "Warehouse B — West" },
        new() { Id = "WH-C", Name = "Warehouse C — Central" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public WarehouseInfo CurrentWarehouse =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId);

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_a70394b665ce47cd97ebfa592edf5113.Services;

/// <summary>
/// Simulates a database query returning the number of low-stock items for a warehouse.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database call with a small delay
        var count = _random.Next(0, 16); // 0–15 inclusive
        return Task.FromResult(count);
    }
}

@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector">
    <label class="warehouse-label" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

.warehouse-selector {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.warehouse-label {
    white-space: nowrap;
    font-weight: 500;
    font-size: 0.875rem;
    color: #555;
}

.form-select {
    min-width: 200px;
}

@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

@if (_lowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto" title="@_lowStockCount low-stock items">
        @_lowStockCount
    </span>
}
else if (_loaded)
{
    <span class="badge bg-success rounded-pill ms-auto" title="No low-stock items">
        0
    </span>
}

@code {
    /// <summary>
    /// When true, this badge instance controls its own polling timer.
    /// Only the Dashboard page badge should poll; the sidebar badge reacts via the shared event.
    /// </summary>
    [Parameter] public bool Poll { get; set; }

    /// <summary>
    /// Raised by the polling instance after each successful refresh so other
    /// components (e.g. the sidebar badge) can piggy-back on the same data.
    /// </summary>
    public static event Action<int>? OnAlertCountUpdated;

    private int _lowStockCount;
    private bool _loaded;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;

        if (Poll)
        {
            StartPolling();
        }
        else
        {
            OnAlertCountUpdated += OnExternalUpdate;
        }

        await RefreshAsync();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                await Task.Delay(TimeSpan.FromSeconds(10), token);
                if (token.IsCancellationRequested) break;

                await InvokeAsync(async () =>
                {
                    await RefreshAsync();
                    OnAlertCountUpdated?.Invoke(_lowStockCount);
                    StateHasChanged();
                });
            }
        }, token);
    }

    private async void OnWarehouseChanged()
    {
        await InvokeAsync(async () =>
        {
            await RefreshAsync();
            if (Poll)
            {
                OnAlertCountUpdated?.Invoke(_lowStockCount);
            }
            StateHasChanged();
        });
    }

    private void OnExternalUpdate(int count)
    {
        InvokeAsync(() =>
        {
            _lowStockCount = count;
            _loaded = true;
            StateHasChanged();
        });
    }

    private async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _loaded = true;
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        WarehouseState.OnChange -= OnWarehouseChanged;
        OnAlertCountUpdated -= OnExternalUpdate;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouse.Name</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Site</h5>
        <p class="card-text fs-4">
            <strong>@WarehouseState.CurrentWarehouse.Name</strong>
            <span class="text-muted ms-2">(@WarehouseState.CurrentWarehouseId)</span>
        </p>
    </div>
</div>

<div class="row">
    <div class="col-md-4">
        <div class="card text-white bg-@(_lowStockCount > 0 ? "danger" : "success") mb-3">
            <div class="card-header">Low-Stock Alerts</div>
            <div class="card-body">
                <h2 class="card-title display-4">@_lowStockCount</h2>
                <p class="card-text">items below minimum levels</p>
                <AlertBadge Poll="true" />
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card border-primary mb-3">
            <div class="card-header">Polling Status</div>
            <div class="card-body">
                <p class="card-text">
                    Refreshing every <strong>10 seconds</strong><br />
                    Last update: <span class="text-muted">@_lastRefresh.ToString("T")</span>
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card border-secondary mb-3">
            <div class="card-header">User Session</div>
            <div class="card-body">
                <p class="card-text">
                    Session scoped to this browser tab.<br />
                    Other managers see their own data.
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    private int _lowStockCount;
    private DateTime _lastRefresh;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertBadge.OnAlertCountUpdated += OnAlertUpdated;
        await RefreshAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                await Task.Delay(TimeSpan.FromSeconds(10), token);
                if (token.IsCancellationRequested) break;

                await InvokeAsync(async () =>
                {
                    await RefreshAsync();
                    StateHasChanged();
                });
            }
        }, token);
    }

    private async void OnWarehouseChanged()
    {
        await InvokeAsync(async () =>
        {
            await RefreshAsync();
            StartPolling(); // restart timer on warehouse switch
            StateHasChanged();
        });
    }

    private void OnAlertUpdated(int count)
    {
        InvokeAsync(() =>
        {
            _lowStockCount = count;
            _lastRefresh = DateTime.Now;
            StateHasChanged();
        });
    }

    private async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastRefresh = DateTime.Now;
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertBadge.OnAlertCountUpdated -= OnAlertUpdated;
    }
}

