@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

@if (_lowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto" title="@_lowStockCount low-stock items">
        @_lowStockCount
    </span>
}
else if (_loaded)
{
    <span class="badge bg-success rounded-pill ms-auto" title="No low-stock items">
        0
    </span>
}

@code {
    /// <summary>
    /// When true, this badge instance controls its own polling timer.
    /// Only the Dashboard page badge should poll; the sidebar badge reacts via the shared event.
    /// </summary>
    [Parameter] public bool Poll { get; set; }

    /// <summary>
    /// Raised by the polling instance after each successful refresh so other
    /// components (e.g. the sidebar badge) can piggy-back on the same data.
    /// </summary>
    public static event Action<int>? OnAlertCountUpdated;

    private int _lowStockCount;
    private bool _loaded;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;

        if (Poll)
        {
            StartPolling();
        }
        else
        {
            OnAlertCountUpdated += OnExternalUpdate;
        }

        await RefreshAsync();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                await Task.Delay(TimeSpan.FromSeconds(10), token);
                if (token.IsCancellationRequested) break;

                await InvokeAsync(async () =>
                {
                    await RefreshAsync();
                    OnAlertCountUpdated?.Invoke(_lowStockCount);
                    StateHasChanged();
                });
            }
        }, token);
    }

    private async void OnWarehouseChanged()
    {
        await InvokeAsync(async () =>
        {
            await RefreshAsync();
            if (Poll)
            {
                OnAlertCountUpdated?.Invoke(_lowStockCount);
            }
            StateHasChanged();
        });
    }

    private void OnExternalUpdate(int count)
    {
        InvokeAsync(() =>
        {
            _lowStockCount = count;
            _loaded = true;
            StateHasChanged();
        });
    }

    private async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _loaded = true;
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        WarehouseState.OnChange -= OnWarehouseChanged;
        OnAlertCountUpdated -= OnExternalUpdate;
    }
}

